import type Accessor from "../../core/Accessor.js";

/** @since 5.0 */
export interface Symbol3DAnchorPosition2DProperties extends Partial<Pick<Symbol3DAnchorPosition2D, "x" | "y">> {}

/** @since 5.0 */
export default class Symbol3DAnchorPosition2D extends Accessor {
  constructor(properties: Symbol3DAnchorPosition2DProperties);
  /**
   * Value defining the position relative to the icon's width.
   *
   * @default 0
   * @since 5.0
   */
  accessor x: number;
  /**
   * Value defining the position relative to the icon's height.
   *
   * @default 0
   * @since 5.0
   */
  accessor y: number;
}